window.HK2_LC10 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["The woman is closing a window.", "The woman is setting down some bags.", "The woman is adjusting her coat.", "The woman is leaving a store."], "optko": ["여자가 창문을 닫고 있다.", "여자가 가방들을 내려놓고 있다.", "여자가 자신의 코트 매무새를 정돈하고 있다.", "여자가 상점을 떠나고 있다."], "ans": 3, "audio": "Test10_01.mp3", "img": "hk2_t10_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["They are installing flooring in a room.", "Supplies are leaning against a wall.", "Some carpeting is being torn out.", "They are climbing a set of steps."], "optko": ["그들은 방에서 바닥재를 설치하고 있다.", "물품들이 벽에 기대어 있다.", "카펫 천이 잡아 뜯겨지고 있다.", "그들은 계단을 오르고 있다."], "ans": 0, "audio": "Test10_02.mp3", "img": "hk2_t10_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Lamps have been set up on the floor.", "Necklaces are being tried on by some customers.", "Jewelry is being arranged in a window display.", "Cases in a store have been filled with merchandise."], "optko": ["전등들이 바닥에 설치되어 있다.", "목걸이들이 몇몇 고객들에 의해 착용되고 있다.", "보석이 쇼윈도 진열장에 정리되고 있다.", "가게 안의 케이스들이 상품으로 채워져 있다."], "ans": 3, "audio": "Test10_03.mp3", "img": "hk2_t10_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["A cabinet is being filled with items.", "A piece of furniture is being dusted.", "The woman is hanging up a clock.", "The woman is folding a hand towel."], "optko": ["수납장이 물품들로 가득 채워지고 있다.", "가구 한 점이 먼지가 닦이고 있다.", "여자는 시계를 걸고 있다.", "여자는 손을 닦는 타월을 접고 있다."], "ans": 1, "audio": "Test10_04.mp3", "img": "hk2_t10_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Structures have been built near a hillside.", "Passengers are boarding vessels from the dock.", "A passenger boat is sailing out to sea.", "A flag has been attached to a pole."], "optko": ["건물들이 산비탈 근처에 지어져 있다.", "승객들이 부두에서 배들에 탑승하고 있다.", "여객선 한 대가 바다를 향해 항해하고 있다.", "깃발이 기둥에 달려 있다."], "ans": 0, "audio": "Test10_05.mp3", "img": "hk2_t10_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A musician is performing for a crowd.", "A cable is being plugged into a wall outlet.", "The man has a guitar strapped to his shoulder.", "Equipment is resting on an elevated platform."], "optko": ["음악가가 관중들을 위해 공연하고 있다.", "전선이 벽 콘센트에 꽂히고 있다.", "남자는 기타를 그의 어깨에 끈으로 맸다.", "장비가 높은 단 위에 놓여 있다."], "ans": 2, "audio": "Test10_06.mp3", "img": "hk2_t10_q6.jpg"}, {"n": 7, "part": 2, "q": "Who represented our firm at the recent expo?", "qko": "누가 최근 박람회에서 우리 회사를 대표했나요?", "opts": ["It was held in Chicago.", "Mr. Dawkins will be going.", "The head of the marketing department."], "optko": ["그것은 시카고에서 개최되었어요.", "Mr. Dawkins가 갈 거예요.", "마케팅 부서의 부장이요."], "ans": 2, "audio": "Test10_07.mp3"}, {"n": 8, "part": 2, "q": "You're going to the welcoming party for the new interns, right?", "qko": "당신은 새로운 인턴들을 위한 환영 파티에 갈 예정이죠, 그렇죠?", "opts": ["Everyone from our team will be there.", "I'm glad it has been going well.", "I sent out invitations last week."], "optko": ["우리 팀 모두가 그곳에 갈 거예요.", "그것이 잘 되어 간다니 기쁘네요.", "제가 지난주에 초대장을 보냈어요."], "ans": 0, "audio": "Test10_08.mp3"}, {"n": 9, "part": 2, "q": "What problem are you having with the cash machine?", "qko": "당신은 현금 인출기에 관해 어떤 문제를 겪고 계시는가요?", "opts": ["We accept checks too.", "The maintenance person has one.", "My debit card was rejected."], "optko": ["저희는 수표도 받습니다.", "정비 직원이 하나 갖고 있어요.", "제 현금 카드가 거부됐어요."], "ans": 2, "audio": "Test10_09.mp3"}, {"n": 10, "part": 2, "q": "Hasn't Ben decided on a vacation destination?", "qko": "Ben이 휴가지를 결정하지 않았나요?", "opts": ["No, we stayed in Brisbane.", "I don't believe so.", "A vacation package."], "optko": ["아니요, 우리는 브리즈번에 머물렀어요.", "아닌 것 같아요.", "휴가 패키지요."], "ans": 1, "audio": "Test10_10.mp3"}, {"n": 11, "part": 2, "q": "Jamie, would you schedule me an appointment with the director?", "qko": "Jamie, 관리자와 저의 약속 일정을 잡아주시겠어요?", "opts": ["Yes, let me draw you a map.", "Your reservation was canceled.", "I'll get on it right away."], "optko": ["네, 제가 약도를 그려드릴게요.", "당신의 예약은 취소되었어요.", "지금 바로 할게요."], "ans": 2, "audio": "Test10_11.mp3"}, {"n": 12, "part": 2, "q": "You have this shirt also available in small, don't you?", "qko": "이 셔츠는 작은 사이즈로도 있죠, 그렇지 않나요?", "opts": ["Actually, that size is sold out.", "I often visit this mall.", "The red dress is cheaper."], "optko": ["사실, 그 사이즈는 다 팔렸어요.", "저는 종종 이 쇼핑몰을 방문해요.", "빨간색 드레스가 더 저렴해요."], "ans": 0, "audio": "Test10_12.mp3"}, {"n": 13, "part": 2, "q": "When will the acquisition be announced?", "qko": "기업 인수는 언제 발표될까요?", "opts": ["Not for another week.", "The merger was very profitable.", "I start the position tomorrow."], "optko": ["다음 주까지는 아니에요.", "합병은 매우 수익성이 있었어요.", "저는 내일 그 일자리를 시작해요."], "ans": 0, "audio": "Test10_13.mp3"}, {"n": 14, "part": 2, "q": "Is someone sitting here, or can I take this chair?", "qko": "누가 여기 앉나요, 아니면 제가 이 의자에 앉아도 되나요?", "opts": ["I've been there before.", "It will take about an hour.", "My friend is using it, I'm afraid."], "optko": ["저는 전에 그곳에 가본 적이 있어요.", "그것은 1시간 정도 걸릴 거예요.", "죄송하지만, 제 친구가 그걸 사용하고 있어요."], "ans": 2, "audio": "Test10_14.mp3"}, {"n": 15, "part": 2, "q": "Who's receiving the Employee of the Month Award?", "qko": "누가 이달의 직원상을 받나요?", "opts": ["Later this evening.", "Mr. Kenichi, most likely.", "Just forward them to me."], "optko": ["오늘 저녁 늦게요.", "아마도, Mr. Kenichi일 거예요.", "그냥 그것들을 제게 보내주세요."], "ans": 1, "audio": "Test10_15.mp3"}, {"n": 16, "part": 2, "q": "Why don't you buy an extra monitor for your computer?", "qko": "당신의 컴퓨터를 위한 추가의 모니터를 구매하는 게 어떤가요?", "opts": ["I already bought tickets for that.", "I'd like that, but my budget is too tight.", "That sounds like a good bargain."], "optko": ["그것을 위한 표를 벌써 구매했어요.", "그러고 싶지만, 제 예산이 너무 빠듯해요.", "싸게 잘 산 물건인 것 같네요."], "ans": 1, "audio": "Test10_16.mp3"}, {"n": 17, "part": 2, "q": "Did we get the results from last week's audit?", "qko": "우리가 지난주 회계 감사의 결과를 받았나요?", "opts": ["You're right. It's pretty odd.", "Yes, it's occurring in the auditorium.", "We'll receive them later today."], "optko": ["맞아요. 그건 좀 이상해요.", "네, 강당에서 시행되고 있어요.", "오늘 늦게 받을 거예요."], "ans": 2, "audio": "Test10_17.mp3"}, {"n": 18, "part": 2, "q": "When did Amit originally establish his business?", "qko": "Amit은 그의 사업체를 언제 처음 설립했나요?", "opts": ["The store opens at 8 A.M.", "A little over two years ago.", "Just around the corner."], "optko": ["그 가게는 오전 8시에 문을 열어요.", "2년 남짓 전에요.", "바로 모퉁이만 돌면요."], "ans": 1, "audio": "Test10_18.mp3"}, {"n": 19, "part": 2, "q": "Which of these briefcases should I buy?", "qko": "이 서류 가방들 중 제가 어느 것을 사야 할까요?", "opts": ["They're both very nice.", "Yes, to replace my old one.", "Thanks. I got them online."], "optko": ["그것들을 둘 다 아주 좋네요.", "네, 제 낡은 것을 교체하기 위해서요.", "감사합니다. 전 그것들을 온라인에서 샀어요."], "ans": 0, "audio": "Test10_19.mp3"}, {"n": 20, "part": 2, "q": "Which applicant do you think we should hire?", "qko": "우리가 어떤 지원자를 채용해야 한다고 생각하시나요?", "opts": ["It depends on the interview results.", "Several people have applied for the position.", "The company is opening a new branch."], "optko": ["그건 면접 결과에 달려 있어요.", "여러 사람들이 그 일자리에 지원했어요.", "회사는 새로운 지사를 열 거예요."], "ans": 0, "audio": "Test10_20.mp3"}, {"n": 21, "part": 2, "q": "Everyone seemed to enjoy the gathering last night.", "qko": "모든 사람들이 어젯밤 모임을 즐기는 것 같았어요.", "opts": ["At George's house in the country.", "A reservation for three nights.", "Yes, they had a good time."], "optko": ["시골에 있는 George의 집에서요.", "3박 예약이요.", "네, 그들은 좋은 시간을 보냈어요."], "ans": 2, "audio": "Test10_21.mp3"}, {"n": 22, "part": 2, "q": "Why don't we take a 10-minute coffee break?", "qko": "우리 10분간 휴식 시간을 갖는 게 어때요?", "opts": ["Can you wait half an hour?", "He has been coughing all day.", "About two days ago."], "optko": ["30분 정도 기다려주시겠어요?", "그는 온종일 기침을 하고 있어요.", "2일 전쯤에요."], "ans": 0, "audio": "Test10_22.mp3"}, {"n": 23, "part": 2, "q": "A customer accidentally left her purse at the register.", "qko": "한 고객이 우연히 자신의 지갑을 금전 등록기에 두고 갔어요.", "opts": ["You can sign up online.", "Place it under the counter for now.", "There are some on the display rack."], "optko": ["당신은 온라인으로 등록할 수 있어요.", "그것을 우선 계산대 아래에 두세요.", "진열용 선반 위에 몇 개 있어요."], "ans": 1, "audio": "Test10_23.mp3"}, {"n": 24, "part": 2, "q": "How did everything go at the real estate convention in Shanghai?", "qko": "상하이에서의 부동산 컨벤션은 어땠나요?", "opts": ["Property values remain the same.", "I made some business connections.", "Near the downtown convention center."], "optko": ["부동산 가치는 여전히 그대로예요.", "제가 몇몇 사업상 거래처들을 만들었어요.", "도심의 컨벤션 센터 근처요."], "ans": 1, "audio": "Test10_24.mp3"}, {"n": 25, "part": 2, "q": "Should we rearrange the layout of the shop?", "qko": "우리가 가게의 배치를 바꿔야 할까요?", "opts": ["This is her favorite boutique.", "Yes, a few of them.", "I'd rather not."], "optko": ["이곳은 그녀가 가장 좋아하는 부티크예요.", "네, 그것들 중 몇 개요.", "안 하는 편이 낫겠어요."], "ans": 2, "audio": "Test10_25.mp3"}, {"n": 26, "part": 2, "q": "Why aren't the salespeople at their desks?", "qko": "판매원들이 왜 그들의 판매대에 있지 않나요?", "opts": ["Let's have the sales team help.", "Some additional telemarketers.", "They are in the conference room."], "optko": ["영업팀이 도와주게 하죠.", "추가 텔레마케터들이요.", "그들은 회의실에 있어요."], "ans": 2, "audio": "Test10_26.mp3"}, {"n": 27, "part": 2, "q": "Landscapers are going to plant rose bushes out front this morning.", "qko": "오늘 아침에 조경사들이 입구 쪽에 장미 덤불을 심을 거예요.", "opts": ["Why wasn't I informed sooner?", "Yesterday afternoon.", "The gardening course has a fee."], "optko": ["왜 미리 알려주지 않았나요?", "어제 오후요.", "원예 강좌는 수업료가 있어요."], "ans": 0, "audio": "Test10_27.mp3"}, {"n": 28, "part": 2, "q": "Haven't you already been accepted to a college?", "qko": "당신은 이미 대학에 합격하지 않았나요?", "opts": ["Here are your course materials.", "Yes, it's been filled out.", "Quite a few, actually."], "optko": ["여기 당신의 강의 자료들이 있어요.", "네, 그것은 작성됐어요.", "사실은, 꽤 여러 군데예요."], "ans": 2, "audio": "Test10_28.mp3"}, {"n": 29, "part": 2, "q": "Beginning next month, all personnel will be required to use security badges.", "qko": "다음 달부터, 모든 직원들이 보안 신분증을 사용하도록 요구될 거예요.", "opts": ["We'd better notify the employees soon then.", "The president is obligated to attend.", "State safety regulations."], "optko": ["그렇다면 우리는 직원들에게 빨리 알리는 게 좋겠어요.", "회장님은 참석하실 의무가 있어요.", "주 보안 규정들이요."], "ans": 0, "audio": "Test10_29.mp3"}, {"n": 30, "part": 2, "q": "Aren't our subscription levels continuing to increase?", "qko": "우리의 기부금 규모가 지속적으로 증가하고 있지 않나요?", "opts": ["You have to refill your prescription.", "According to the head accountant.", "I'm continuing to review applications."], "optko": ["당신은 처방전대로 약을 다시 지어야 해요.", "수석 회계사에 따르면요.", "저는 신청서들을 계속 검토하고 있어요."], "ans": 1, "audio": "Test10_30.mp3"}, {"n": 31, "part": 2, "q": "What did the manufacturer do when you asked for a refund?", "qko": "당신이 환불을 요청했을 때 제조사는 무엇을 했나요?", "opts": ["One of the warehouses at the factory.", "They accommodated my request.", "We changed the return policy."], "optko": ["공장에 있는 창고들 중 하나요.", "그들은 제 요청을 수용했어요.", "우리는 반품 정책을 변경했어요."], "ans": 1, "audio": "Test10_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test10_32-34.mp3", "qs": [{"n": 32, "q": "Why is the man calling?", "opts": ["To discuss preparations", "To explain an issue", "To request handouts", "To get a quotation"], "ans": 0, "ko": "남자는 왜 전화를 하고 있는가?"}, {"n": 33, "q": "What problem does the woman mention?", "opts": ["A budget is too tight.", "A payment was not made.", "A concert must be postponed.", "A band has other plans."], "ans": 3, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 34, "q": "What does the man recommend?", "opts": ["Canceling an event", "Contacting another group", "Inviting fewer guests", "Finding a different venue"], "ans": 1, "ko": "남자는 무엇을 권하는가?"}], "script": [{"sp": "M", "en": "This is Dennis Walden, head of The Music Collective. I recently hired your agency to organize and promote a charity concert for my foundation. I'm calling to see how the preparations are coming along.", "ko": "저는 The Music Collective의 사장 Dennis Walden입니다. 우리 재단을 위한 자선 콘서트를 준비하고 홍보하기 위해 최근에 귀하의 대행사를 고용했는데요. 준비가 어떻게 되어 가고 있는지 확인하기 위해 전화드립니다."}, {"sp": "W", "en": "For the most part, things are going well, Mr. Walden. However, the band that you want to book will be performing elsewhere on the night of the event. So, I'm afraid they can't participate.", "ko": "대부분은 잘 진행되고 있습니다, Mr. Walden. 하지만, 귀하께서 예약하길 원하시는 밴드는 그 행사일 밤에 다른 곳에서 공연할 예정이에요. 그래서, 유감스럽게도 그들은 참여하지 못할 것 같습니다."}, {"sp": "M", "en": "Hmm . . . In that case, why don't you see if the Sifters are available? They played at one of our fund-raising banquets last year, and everyone seemed to enjoy their music. You should get in touch with them.", "ko": "흠… 그렇다면, the Sifters가 시간이 있는지 확인하는 건 어때요? 그들은 작년에 저희의 기금 모금 연회 중 하나에서 연주했는데, 모든 사람들이 그들의 음악을 즐기는 것 같았어요. 그들에게 연락해 보시는 게 좋겠어요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test10_35-37.mp3", "qs": [{"n": 35, "q": "What is being launched?", "opts": ["A trade magazine", "A company Web site", "A clothing collection", "An electronic device"], "ans": 3, "ko": "무엇이 출시되고 있는가?"}, {"n": 36, "q": "What is mentioned about the event?", "opts": ["It has attracted many online writers.", "It was organized by several teams.", "It has impressed the company president.", "It was promoted in a local newspaper."], "ans": 0, "ko": "행사에 관해 무엇이 언급되는가?"}, {"n": 37, "q": "According to the man, what does Emily Scott plan to do?", "opts": ["Publish an article", "Try out a product", "Attend a future launch", "Review a Web site"], "ans": 0, "ko": "남자에 따르면, Emily Scott은 무엇을 할 계획인가?"}], "script": [{"sp": "M", "en": "This launch for our firm's GPS navigation device is going very well. It might be the most successful event that I've overseen since I started working as the manager of the product development team.", "ko": "우리 회사의 GPS 내비게이션 기기의 이번 출시 행사가 아주 잘 진행되고 있어요. 제가 제품 개발팀의 관리자로서 일하기 시작한 이래로 제가 감독한 가장 성공적인 행사일 것 같아요."}, {"sp": "W", "en": "Yes, a lot of technology bloggers and industry figures have shown up. They all seem very impressed with the device. Hopefully, they'll bring positive attention to it as well as our firm.", "ko": "네, 많은 기술 블로거 운영자들과 업계의 중요한 인물들이 모습을 드러냈어요. 그들은 모두 그 기기에 깊은 인상을 받은 것 같아요. 그들이 우리 회사뿐만 아니라 그것에도 긍정적인 관심을 가지면 좋겠네요."}, {"sp": "M", "en": "I think they will. In fact, I just spoke with Emily Scott, a staff writer from Everyday Science. She intends to publish a favorable review about our product on her company's Web site.", "ko": "그럴 거라고 생각해요. 사실, 제가 방금 Everyday Science지의 전속 기자인 Emily Scott과 이야기를 나누었어요. 그녀는 그녀의 회사 웹사이트에 우리 제품에 대한 호의적인 논평을 게재하려고 생각 중이에요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음 → 캐나다식 발음", "audio": "Test10_38-40.mp3", "qs": [{"n": 38, "q": "What are the speakers mainly discussing?", "opts": ["A printer malfunction", "A magazine article", "An upcoming publication", "A textbook author"], "ans": 2, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 39, "q": "What is the problem?", "opts": ["Some content was printed incorrectly.", "Some data in a graph is inaccurate.", "Some pages are missing from a book.", "Some materials were not printed on schedule."], "ans": 0, "ko": "무엇이 문제인가?"}, {"n": 40, "q": "What will the woman probably do next?", "opts": ["Call a manager", "Make a revision", "Review a process", "Visit a company"], "ans": 3, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M1", "en": "I'm glad you're both here. I was just going through the sample we received from the printer.", "ko": "두 분 다 여기 계셔서 다행이에요. 저는 우리가 인쇄소로부터 받은 샘플을 이제 막 살펴보고 있었어요."}, {"sp": "W", "en": "Do you mean the Psychology 101 textbook that we will publish on March 31?", "ko": "3월 31일에 출간할 심리학 입문 교과서를 말씀하시는 건가요?"}, {"sp": "M1", "en": "Right. But we have a problem. The graph on page 234 was printed upside down. We will have to postpone publication because there are 5,000 copies that will need to be reprinted.", "ko": "맞아요. 그런데 문제가 있어요. 234페이지에 있는 그래프가 거꾸로 인쇄되었어요. 5,000부가 다시 인쇄되어야 할 것이기 때문에 우리는 출간을 연기해야 할 거예요."}, {"sp": "M2", "en": "You know, there was a similar situation last year, and the printer just replaced the page that contained the error. The entire process took only a few days.", "ko": "있잖아요, 작년에 비슷한 일이 있었는데, 인쇄소에서 오류가 있는 페이지만 교체했어요. 전체 과정은 며칠밖에 걸리지 않았고요."}, {"sp": "M1", "en": "That's a relief. I'll call the printer now and explain the situation.", "ko": "그거 다행이네요. 제가 지금 인쇄소에 전화해서 상황을 설명할게요."}, {"sp": "W", "en": "Actually, I have to discuss some shipping charges with the manager of the print shop. I'll go there now and deal with this as well.", "ko": "사실, 저는 인쇄소의 관리자와 배송 비용에 대해 논의해야 해요. 제가 지금 거기로 가서 이 문제도 처리할게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test10_41-43.mp3", "qs": [{"n": 41, "q": "Why does the woman visit the shop?", "opts": ["To upgrade her insurance", "To have a tool repaired", "To rent some equipment", "To enroll in some classes"], "ans": 2, "ko": "여자는 왜 가게에 방문하는가?"}, {"n": 42, "q": "What does the woman mean when she says, \"I can practice with them after I complete the lessons\"?", "opts": ["She accepts a requirement.", "She will extend a contract.", "She is willing to pay extra.", "She wants a rule to be changed."], "ans": 0, "ko": "여자는 \"저는 수업을 끝마친 후에 그것들로 연습할 수 있어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 43, "q": "What will the man probably do next?", "opts": ["Explain a lesson schedule", "Process a fee payment", "Provide some insurance forms", "Examine an identification card"], "ans": 3, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Good morning. I'm planning to take golf lessons, and I'd like to rent a set of clubs from your shop. I'll need them for three months, starting from today.", "ko": "안녕하세요. 골프 수업을 받으려고 계획 중이라서, 당신의 가게에서 골프채 세트를 빌리고 싶습니다. 저는 오늘부터 석 달 동안 그것들이 필요할 거예요."}, {"sp": "M", "en": "Not a problem. Our rental prices are quite competitive, and the fee includes damage insurance for the clubs. However, we recently modified our rental rules, so you'll have to rent them for at least six months, which is a bit too long for you, I think.", "ko": "물론이죠. 저희 대여 비용은 상당히 경쟁력 있고, 이 요금은 골프채에 대한 손해 보험도 포함합니다. 하지만, 저희가 최근에 대여 규정을 변경해서, 적어도 여섯 달 동안은 대여하셔야 할 텐데, 제 생각에 당신에게 조금 긴 것 같네요."}, {"sp": "W", "en": "Hmm . . . I can practice with them after I complete the lessons.", "ko": "음… 저는 수업을 끝마친 후에 그것들로 연습할 수 있어요."}, {"sp": "M", "en": "All right. A piece of photo ID is required to rent our equipment, so I'll need to look at that first.", "ko": "좋습니다. 저희 장비를 대여하시려면 사진이 있는 신분증이 필요하기 때문에, 먼저 그것부터 봐야 합니다."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test10_44-46.mp3", "qs": [{"n": 44, "q": "What caused the woman to be late?", "opts": ["An extended meeting", "Road congestion", "Inclement weather", "An automobile accident"], "ans": 1, "ko": "무엇이 여자가 지각하도록 야기했는가?"}, {"n": 45, "q": "Why does the woman drive to work?", "opts": ["She carpools with other coworkers.", "She commutes from a different town.", "She does not like walking in cold weather.", "She does not like riding public transportation."], "ans": 2, "ko": "여자는 왜 차로 출근하는가?"}, {"n": 46, "q": "What does the man say he will do for the woman?", "opts": ["Give her a map", "Drive her to the office", "Send her a link", "Meet her at a station"], "ans": 2, "ko": "남자는 여자를 위해 무엇을 해주겠다고 말하는가?"}], "script": [{"sp": "W", "en": "Sorry I'm a few minutes late, but it took me almost two hours to drive to the office today. Traffic on the freeway was extremely slow.", "ko": "좀 늦어서 죄송해요, 그런데 오늘 사무실까지 운전해서 오는 데 거의 2시간이나 걸렸어요. 고속도로의 교통이 너무 느렸어요."}, {"sp": "M", "en": "Really? I can't believe it took you so long. Why don't you just use public transportation? I'm sure it would be a lot faster than driving.", "ko": "정말이에요? 그렇게 오래 걸렸다니 믿을 수 없네요. 그냥 대중교통을 이용하는 게 어때요? 분명히 운전하는 것보다 훨씬 더 빠를 거예요."}, {"sp": "W", "en": "Well, the nearest subway or bus station from my apartment is 20 minutes on foot. With the cold weather here, I prefer not to walk. So, I usually end up taking my car.", "ko": "글쎄요, 제 아파트에서 가장 가까운 지하철역이나 버스 정류장은 걸어서 20분이 걸려요. 이곳의 추운 날씨 때문에, 저는 걷지 않는 걸 선호해요. 그래서, 저는 보통 결국 제 차를 가져오게 돼요."}, {"sp": "M", "en": "Actually, the Transport Authority just changed its city bus routes. I think bus 402 now stops in your neighborhood, so that would be really convenient for you. I'll forward you a link to the city Web site for you to review.", "ko": "사실, 교통 당국이 막 시내버스 노선을 변경했어요. 이제 402번 버스가 당신 동네에 서는 것 같으니, 당신에게 매우 편리할 거예요. 당신이 확인할 수 있도록 시 웹사이트 링크를 보내줄게요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test10_47-49.mp3", "qs": [{"n": 47, "q": "Why is the woman calling?", "opts": ["To check an event date", "To cancel a reservation", "To request a ticket refund", "To inquire about a discount"], "ans": 3, "ko": "여자는 왜 전화를 하고 있는가?"}, {"n": 48, "q": "What does the man suggest the woman do?", "opts": ["Attend an exhibit", "Download a coupon", "Contact another employee", "Submit some online forms"], "ans": 2, "ko": "남자는 여자에게 무엇을 하라고 제안하는가?"}, {"n": 49, "q": "Why does the woman say, \"I picked up a brochure yesterday\"?", "opts": ["To explain a decision", "To reject a suggestion", "To confirm a plan", "To point out an error"], "ans": 1, "ko": "여자는 왜 \"저는 어제 소책자를 얻었어요\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Rochester Convention Center. How can I help you?", "ko": "Rochester 컨벤션 센터입니다. 무엇을 도와드릴까요?"}, {"sp": "W", "en": "Good morning. I'm calling about the Westgate Auto Show on May 18. I know that tickets are $20 per person, but I will be attending with the other members of my auto club. Is it possible for us to get a group rate?", "ko": "안녕하세요. 5월 18일에 있을 Westgate 자동차 쇼에 관해 전화드립니다. 입장권이 한 사람당 20달러인 것을 알고 있지만, 저는 자동차 동호회의 다른 회원들과 함께 참석할 거예요. 저희가 단체 요금을 적용받는 것이 가능할까요?"}, {"sp": "M", "en": "Yes. But you'll need to discuss it with Carol Humphrey who is in charge of group ticket sales. Her e-mail address is carol@conventionpro.com.", "ko": "네. 하지만 단체 입장권 판매를 담당하는 Carol Humphrey와 그것을 논의하셔야 할 겁니다. 그녀의 이메일 주소는 carol@conventionpro.com입니다."}, {"sp": "W", "en": "Great. We're really excited about the upcoming exhibit of antique cars.", "ko": "좋아요. 저희는 곧 있을 골동품 자동차 전시회에 대해 정말 들떠 있어요."}, {"sp": "M", "en": "We have some promotional material from the company that is organizing that event. Why don't I send it to you?", "ko": "저희가 그 행사를 주최하는 회사의 홍보 자료들을 갖고 있어요. 제가 당신에게 보내드릴까요?"}, {"sp": "W", "en": "I picked up a brochure yesterday. But thanks.", "ko": "저는 어제 소책자를 얻었어요. 그렇지만 감사합니다."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test10_50-52.mp3", "qs": [{"n": 50, "q": "Why was the man's trip disappointing?", "opts": ["He could not attend a business seminar.", "He was unable to explore a city.", "He had to return home early.", "He was not able to secure a deal."], "ans": 1, "ko": "남자의 여행은 왜 실망스러웠는가?"}, {"n": 51, "q": "According to the woman, what is true about Cape Town?", "opts": ["It is becoming more popular with tourists.", "It is building many modern structures.", "It has several outdoor recreational spaces.", "It has very low levels of rainfall."], "ans": 2, "ko": "여자에 따르면, 케이프타운에 관해 무엇이 사실인가?"}, {"n": 52, "q": "What did the man do in Cape Town?", "opts": ["Attended a lecture", "Photographed a monument", "Visited a park", "Watched a performance"], "ans": 3, "ko": "남자는 케이프타운에서 무엇을 했는가?"}], "script": [{"sp": "W", "en": "I heard that you just returned from your business trip to Cape Town. How did it go?", "ko": "당신이 케이프타운으로 간 출장에서 막 돌아왔다고 들었어요. 어땠나요?"}, {"sp": "M", "en": "Everything related to work went well, but the rest of my time there was a bit disappointing. It rained throughout my stay, so I didn't get a chance to walk around the city.", "ko": "업무와 관련된 모든 것은 잘 진행되었는데, 그곳에서의 나머지 시간은 좀 실망스러웠어요. 제가 머무는 동안 내내 비가 와서, 도시를 돌아다닐 기회를 얻지 못했어요."}, {"sp": "W", "en": "That's a shame. Cape Town has various public parks and some really beautiful monuments. I suppose you weren't able to see any of them.", "ko": "아쉽네요. 케이프타운에는 다양한 공원들과 매우 아름다운 기념물들이 있어요. 당신은 그것들 중 어느 것도 볼 수 없었겠네요."}, {"sp": "M", "en": "No, I had to spend most of my free time in my hotel room. On the day before my departure, I watched a traditional dance at a nearby cultural center, though. It was very interesting.", "ko": "네, 자유 시간의 대부분을 호텔 방에서 보내야 했어요. 하지만 출발하기 하루 전날에, 저는 근처 문화 센터에서 전통 무용을 관람했어요. 정말 즐거웠어요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test10_53-55.mp3", "qs": [{"n": 53, "q": "What type of event is taking place?", "opts": ["A convention", "An investors meeting", "A corporate outing", "A marketing class"], "ans": 0, "ko": "어떤 종류의 행사가 열리고 있는가?"}, {"n": 54, "q": "According to the woman, what were attendees impressed with?", "opts": ["A foreign product", "An online service", "A finance talk", "An investment opportunity"], "ans": 2, "ko": "여자에 따르면, 참석자들은 무엇에 깊은 인상을 받았는가?"}, {"n": 55, "q": "According to the man, what will be uploaded to a Web site?", "opts": ["Video recordings", "Event photos", "Lecture transcripts", "Attendee feedback"], "ans": 0, "ko": "남자에 따르면, 무엇이 웹사이트에 올라갈 것인가?"}], "script": [{"sp": "W", "en": "A few of the convention attendees are curious whether video or audio clips of today's talks will be posted online. Do you know if that is going to happen?", "ko": "컨벤션 참석자들 몇 명이 오늘 강연의 비디오나 음성 클립들이 온라인으로 게시될지 궁금해해요. 그렇게 될지 알고 계시나요?"}, {"sp": "M", "en": "Only some of them will be shared following the event. Is there a particular lecture that people are inquiring about?", "ko": "그것들 중 일부만 행사 이후에 공유될 거예요. 사람들이 문의하고 있는 특정 강연이 있나요?"}, {"sp": "W", "en": "Yes, a number of attendees have asked about Lillian Kraft's talk on investing in foreign markets. Many of them seem to have been quite impressed.", "ko": "네, 많은 참석자들이 Lillian Kraft의 외국 시장 투자에 관한 강연에 대해 물어봤어요. 그들 중 많은 사람들이 꽤 깊은 인상을 받은 것 같았어요."}, {"sp": "M", "en": "She is the keynote speaker, so video clips including her talk will definitely be uploaded to the Web site. You can inform anyone who inquires about it that they will be able to access them later on.", "ko": "그녀는 기조연설자라서, 그녀의 강연을 포함한 비디오 클립들은 웹사이트에 분명히 올라갈 거예요. 누구든 그것에 관해 문의하는 사람들에게 나중에 그것들을 이용할 수 있을 거라고 알려주시면 돼요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test10_56-58.mp3", "qs": [{"n": 56, "q": "Who is Felicity Gifford?", "opts": ["A workshop teacher", "A class participant", "A university professor", "A library employee"], "ans": 1, "ko": "Felicity Gifford는 누구인가?"}, {"n": 57, "q": "Why will the woman rearrange some furniture?", "opts": ["An event will have many attendees.", "A venue has been changed.", "An activity has been planned by the instructor.", "A classroom will be cleaned."], "ans": 0, "ko": "여자는 왜 몇몇 가구를 재배치할 것인가?"}, {"n": 58, "q": "What does the man recommend?", "opts": ["Removing unnecessary seating", "Keeping a door open", "Handing out library brochures", "Having an employee at the door"], "ans": 3, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Felicity Gifford, who is one of the students coming to the library for today's job-search workshop, uses a wheelchair. We need to make sure she's able to comfortably pull her wheelchair up to a table.", "ko": "오늘의 구직 워크숍을 위해 도서관에 오는 학생들 중 한 명인 Felicity Gifford는 휠체어를 사용해요. 그녀가 책상까지 수월하게 휠체어를 밀고 올 수 있도록 확실히 해야 합니다."}, {"sp": "W", "en": "Nick and I can take care of that since we're planning to shift some of the furniture around anyway. More people than anticipated registered for the class, so the tables and chairs must be rearranged to make better use of the space.", "ko": "Nick과 제가 어차피 몇 가지 가구를 옮기려고 계획하고 있기 때문에 그것을 처리할 수 있어요. 예상보다 더 많은 사람들이 수업에 등록해서, 공간을 더 잘 활용할 수 있도록 책상과 의자들이 재배치되어야 해요."}, {"sp": "M", "en": "All right. Also, if a lot of people are coming, we should have one of our staff members welcome participants at the front door and help them find their seats.", "ko": "좋아요. 또한, 만약 많은 사람들이 온다면, 우리 직원들 중 한 명이 정문에서 참석자들을 맞이하고 그들이 자리를 찾는 것을 도와주도록 해야 해요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test10_59-61.mp3", "qs": [{"n": 59, "q": "What are the speakers mainly discussing?", "opts": ["Membership levels", "Contract negotiations", "A poster for an association", "A brochure for a festival"], "ans": 2, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 60, "q": "Where does the man most likely work?", "opts": ["At a graphic design firm", "At a community center", "At a law office", "At a print shop"], "ans": 2, "ko": "남자는 어디에서 일하는 것 같은가?"}, {"n": 61, "q": "What does the man agree to do?", "opts": ["Volunteer his services", "Join an association", "Coordinate with a business", "Read over a document"], "ans": 0, "ko": "남자는 무엇을 하기로 동의하는가?"}], "script": [{"sp": "W", "en": "I'm looking for someone to help me create a poster to increase awareness of our community association. Another member told me that you are a graphic designer. But I thought that you work at a law firm.", "ko": "저는 우리의 지역 협회의 인지도를 높이기 위한 포스터를 만드는 데 도움을 줄 사람을 찾고 있는데요. 다른 회원이 당신이 그래픽 디자이너라는 걸 저에게 말해주었어요. 그런데 저는 당신이 법률 회사에서 일하는 줄 알았어요."}, {"sp": "M", "en": "Yes, I'm a legal assistant at Beale and Associates here in town. However, I do freelance graphic design to make extra money on the side.", "ko": "맞아요, 저는 이 지역에 있는 Beale and Associates사의 법률 보조예요. 하지만, 추가의 돈을 벌기 위해 부업으로 자유 계약의 그래픽 디자인을 해요."}, {"sp": "W", "en": "Great. Well, we want to place the poster in cafes and other businesses in the neighborhood. Hopefully, it will draw in more people to our weekly meetings. Would you be willing to make it?", "ko": "좋아요. 음, 저희는 우리 인근의 카페들과 다른 업체들에 포스터를 배치하고 싶어요. 바라건대, 그건 우리의 주간 모임에 더 많은 사람들을 끌어올 거예요. 그것을 만들어주실 생각이 있으신가요?"}, {"sp": "M", "en": "Of course! I'd be happy to volunteer my time to the association. I'll begin working on it this evening.", "ko": "당연하죠! 저는 기꺼이 제 시간을 협회에 지원하고 싶어요. 오늘 저녁에 작업을 시작하도록 할게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test10_62-64.mp3", "qs": [{"n": 62, "q": "How did the woman learn about a cleaning service?", "opts": ["By using a search engine", "By checking social media", "By reading a flyer", "By talking to a relative"], "ans": 3, "ko": "여자는 어떻게 청소 서비스에 관해 알게 되었는가?"}, {"n": 63, "q": "Look at the graphic. Which package will the woman probably choose?", "opts": ["Basic", "Standard", "Superior", "Ultimate"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어느 패키지를 고를 것 같은가?"}, {"n": 64, "q": "When will workers most likely visit the woman's home?", "opts": ["On Saturday", "On Sunday", "On Monday", "On Tuesday"], "ans": 2, "ko": "작업자들은 언제 여자의 집을 방문할 것 같은가?"}], "script": [{"sp": "M", "en": "Thank you for calling EZ Home Cleaning. What can I assist you with today?", "ko": "EZ Home Cleaning사에 전화해주셔서 감사합니다. 오늘 무엇을 도와드릴까요?"}, {"sp": "W", "en": "My uncle referred me to your company, and I'm interested in your services. I need my floors vacuumed, my furniture dusted, and my bathrooms cleaned.", "ko": "제 삼촌이 귀사를 추천해주셔서, 귀사의 서비스에 관심이 있어요. 저는 바닥을 진공청소기로 청소하고, 가구의 먼지를 털고, 화장실을 청소해야 해요."}, {"sp": "M", "en": "We can do that for $70. If you'd like your windows cleaned as well, we have another package that costs $80.", "ko": "저희는 그것들을 70달러에 해드릴 수 있습니다. 창문도 청소하고 싶으시다면, 80달러의 다른 패키지가 있습니다."}, {"sp": "W", "en": "That won't be necessary. Would you be able to send someone to my house this Saturday or Sunday?", "ko": "그건 필요하지 않을 것 같아요. 토요일이나 일요일에 저희 집으로 사람을 보내주실 수 있나요?"}, {"sp": "M", "en": "Actually, we are fully booked for the weekend, but we can do it on Monday at 10:00 A.M. or Tuesday at 7:00 P.M.", "ko": "실은, 주말 예약은 다 찼습니다만, 월요일 오전 10시나 화요일 오후 7시에 해드릴 수 있습니다."}, {"sp": "W", "en": "Monday would work best for me.", "ko": "월요일이 저에게 가장 좋을 것 같네요."}], "gimg": "hk2_t10_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test10_65-67.mp3", "qs": [{"n": 65, "q": "Why is the man changing his reservation time?", "opts": ["He will be attending a meeting.", "He will be calling a client.", "He will be visiting another office.", "He will be working late."], "ans": 0, "ko": "남자는 왜 예약 시간을 변경하고 있는가?"}, {"n": 66, "q": "What does the woman say about the restaurant?", "opts": ["It launched a new Web site.", "It extended its hours.", "It was recently renovated.", "It updated its menu."], "ans": 3, "ko": "여자는 식당에 관해 무엇을 말하는가?"}, {"n": 67, "q": "Look at the graphic. Why will the man be unable to use the coupon?", "opts": ["The expiration date will have passed.", "He will not spend a sufficient amount.", "He will not dine during the specified hours.", "Another promotion is being held."], "ans": 2, "ko": "시각 자료를 보시오. 남자는 왜 쿠폰을 사용할 수 없을 것인가?"}], "script": [{"sp": "M", "en": "Hello, this is Jack Parker. I made a reservation for Friday at 12:30 P.M., but I'd like to move it to . . . um . . . to 6:00 P.M. Some important clients will be at our office for a presentation that afternoon, and I will need to participate.", "ko": "안녕하세요, 저는 Jack Parker입니다. 저는 금요일 오후 12시 30분으로 예약했는데, 저는 그것을… 음… 오후 6시로 옮기고 싶어요. 그날 오후에 중요한 고객들이 발표를 위해 우리 사무실에 오실 거고, 제가 참석해야 하거든요."}, {"sp": "W", "en": "No problem, Mr. Parker. And just to let you know, we recently updated our menu, and there are several new entrées available.", "ko": "문제없습니다, Mr. Parker. 그리고 그냥 알려드리는 건데, 저희는 최근에 메뉴를 업데이트해서, 몇 가지 새로운 주요리가 이용 가능합니다."}, {"sp": "M", "en": "I saw that on your Web site when I downloaded a coupon this morning.", "ko": "오늘 아침에 쿠폰을 내려받으면서 웹사이트에서 봤어요."}, {"sp": "W", "en": "The one for a free entrée? Actually, you won't be able to use that with your reservation for Friday evening. I'm sorry.", "ko": "무료 주요리를 위한 쿠폰이요? 실은, 손님의 금요일 저녁 예약에 그것을 사용하실 수는 없을 거예요. 죄송합니다."}, {"sp": "M", "en": "Oh, I see the problem. I'll use it some other time, then.", "ko": "아, 무엇이 문제인지 알겠네요. 그럼 다음에 이것을 사용할게요."}], "gimg": "hk2_t10_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test10_68-70.mp3", "qs": [{"n": 68, "q": "What does the woman inquire about?", "opts": ["The reason for a transfer", "The time of an arrival", "The origin of some animals", "The location of a zoo"], "ans": 1, "ko": "여자는 무엇에 관해 문의하는가?"}, {"n": 69, "q": "What does the man request the woman do?", "opts": ["Check a facility's condition", "Transport a food container", "Clean a building exterior", "Train an animal for a show"], "ans": 0, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}, {"n": 70, "q": "Look at the graphic. Where will the new animals live?", "opts": ["In Enclosure 1", "In Enclosure 2", "In Enclosure 3", "In Enclosure 4"], "ans": 3, "ko": "시각 자료를 보시오. 새로운 동물들은 어디에서 생활할 것인가?"}], "script": [{"sp": "M", "en": "Juliana, two new animals are being transferred to our zoo tomorrow.", "ko": "Juliana, 내일 우리 동물원에 새로운 동물 두 마리가 이송될 거예요."}, {"sp": "W", "en": "The pandas—I heard. When will they get here?", "ko": "판다들이라고 들었어요. 그들은 언제 이곳에 도착할까요?"}, {"sp": "M", "en": "About an hour before the zoo opens. Anyway, could you put some bamboo shoots in these buckets? That way, they'll have food when they arrive.", "ko": "동물원이 개장하기 약 한 시간 전이요. 어쨌든, 이 양동이들에 죽순을 좀 넣어 주시겠어요? 그러면, 그들이 도착했을 때 먹을 것이 있을 거예요."}, {"sp": "W", "en": "No problem.", "ko": "물론이죠."}, {"sp": "M", "en": "And after that, please check whether the panda enclosure is clean. If not, we should wash it out this afternoon.", "ko": "그리고 그다음에, 판다 우리가 깨끗한지 확인해주세요. 만약 아니라면, 우리가 오늘 오후에 그곳을 물로 씻어 내야 해요."}, {"sp": "W", "en": "Do you mean the enclosure near the back exit on Lee Drive or the one near the sea life exhibit?", "ko": "Lee길에 있는 후문 근처의 우리를 말씀하시는 건가요 아니면 해양 생물 전시회 근처에 있는 것을 말씀하시는 건가요?"}, {"sp": "M", "en": "I'm talking about the one on Parker Lane.", "ko": "저는 Parker길에 있는 것을 말하는 거예요."}], "gimg": "hk2_t10_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test10_71-73.mp3", "qs": [{"n": 71, "q": "Where most likely are the listeners?", "opts": ["At a bookstore", "At a university", "At a museum", "At a library"], "ans": 3, "ko": "청자들은 어디에 있는 것 같은가?"}, {"n": 72, "q": "What does the speaker say will take place?", "opts": ["Library cards will be distributed.", "Books will be sold to visitors.", "Attendees will compete in a contest.", "Prices will be reduced."], "ans": 1, "ko": "화자는 무슨 일이 일어날 것이라고 말하는가?"}, {"n": 73, "q": "Why does the speaker thank Camdale Enterprises?", "opts": ["For funding an event", "For creating a scholarship", "For promoting a fair", "For sending novels"], "ans": 0, "ko": "화자는 왜 Camdale사에 감사하는가?"}], "script": [{"sp": "M", "en": "Welcome to the annual South Hill Library Book Fair. Each autumn, we host a variety of special activities to encourage reading among local residents. In addition to offering a vast variety of both new and used books for sale, we are pleased to present a special event this year—an exhibition of rare first-edition books by early American authors. These publications are on loan from the University of Minneapolis and will be displayed in the lobby for the duration of the fair. And I would like to thank this year's corporate sponsor, Camdale Enterprises, for their financial support.", "ko": "South Hill 도서관의 연례 도서 박람회에 오신 것을 환영합니다. 매년 가을에, 저희는 지역 주민들 사이에 독서를 장려하기 위해 다양한 특별 활동들을 주최합니다. 판매를 위해 방대한 종류의 신간 및 중고 서적들을 제공하는 것에 더하여, 저희는 올해 특별 행사로 초기 미국 작가들의 희귀한 초판 책 전시를 보여드리게 되어 기쁩니다. 이 서적들은 미니애폴리스 대학교에서 대여했으며 박람회 기간 동안 로비에 전시될 것입니다. 그리고 저는 올해의 기업 후원 업체인 Camdale사에 재정 후원에 대해 감사드리고 싶습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test10_74-76.mp3", "qs": [{"n": 74, "q": "What does the speaker say about the municipal government?", "opts": ["It provided funds for an event.", "It launched a promotional campaign.", "It regulated the use of fireworks.", "It invited industry leaders to a gathering."], "ans": 0, "ko": "화자는 시 정부에 관해 무엇을 말하는가?"}, {"n": 75, "q": "What does the speaker imply when he says, \"thousands of people are expected to travel to Harrisburg over the weekend\"?", "opts": ["A show has grown in size.", "A festival has economic benefits.", "Tourists will have limited hotel options.", "Organizers need to change arrangements."], "ans": 1, "ko": "화자는 \"수천 명의 사람들이 주말 동안 해리스버그로 여행을 올 것이라 예상됩니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 76, "q": "What will listeners probably hear next?", "opts": ["An interview", "A commercial", "A talk show", "A traffic report"], "ans": 3, "ko": "청자들은 다음에 무엇을 들을 것 같은가?"}], "script": [{"sp": "M", "en": "You're listening to WRP 99.9. The 20th annual Harrisburg Fireworks Fest is set to take place on Saturday evening. It will be held on the north end of Keaton Lake. The celebration, which has been made possible through funding by the municipal government, will feature an hour-long firework show. The city's hotel and restaurant industry are looking forward to the event, as thousands of people are expected to travel to Harrisburg over the weekend. Now, stay tuned for details about road congestion throughout the metro area.", "ko": "여러분은 WRP 99.9를 듣고 계십니다. 20번째 연례 해리스버그 불꽃놀이 축제가 토요일 저녁에 개최될 준비가 되었습니다. 이 축제는 Keaton 호수의 북쪽 끝에서 열릴 것입니다. 시 정부에 의한 재정 지원을 통해 가능할 수 있었던 이 축제는 한 시간의 불꽃놀이 쇼를 특별히 포함할 것입니다. 수천 명의 사람들이 주말 동안 해리스버그로 여행을 올 것이라 예상되기 때문에, 이 도시의 호텔과 식당 업계는 이 행사를 기대하고 있습니다. 이제, 도시 전역에 걸친 도로 정체에 관한 세부 사항들을 위해 채널을 고정해 주십시오."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test10_77-79.mp3", "qs": [{"n": 77, "q": "Why are camera flashes prohibited?", "opts": ["They upset the performers.", "They distract the guide.", "They frighten the wildlife.", "They bother other guests."], "ans": 2, "ko": "카메라 플래시는 왜 금지되는가?"}, {"n": 78, "q": "What does the speaker tell listeners to do?", "opts": ["Leave their bags at the entrance", "Meet at the snack bar", "Take some beverages along", "Remain on the shuttle"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 말하는가?"}, {"n": 79, "q": "According to the speaker, what can listeners do after seeing the African wildlife compound?", "opts": ["Get something to eat", "Browse through some souvenirs", "Look at some displays", "Watch a demonstration"], "ans": 0, "ko": "화자에 따르면, 청자들은 아프리카 야생 동물 지역을 본 뒤에 무엇을 할 수 있는가?"}], "script": [{"sp": "W", "en": "Before we explore the Chakra Wildlife Park, I want you to listen closely to the following instructions and information. First, food is not permitted inside the park. Second, photographs are allowed, but please do not use a flash because the light scares the animals. Third, do not exit the shuttle at any time during the tour. As a reminder, there will be an hour lunch break at the Jungle Café after we're done touring the African wildlife compound. Once everyone has finished eating, we will resume the tour by continuing on to our Asian wildlife compound. OK, if you'll please follow me, we will begin our tour.", "ko": "우리가 Chakra 야생 동물 공원을 탐험하기 전에, 저는 여러분께서 다음의 설명들과 정보를 주의 깊게 들으시길 바랍니다. 첫째로, 공원 안에서 음식은 허용되지 않습니다. 둘째로, 사진은 허용되지만, 빛이 동물들을 겁먹게 하기 때문에 플래시는 사용하지 말아 주십시오. 셋째로, 관광 중 어느 때든지 셔틀버스에서 내리지 마십시오. 다시 한번 상기시켜 드리자면, 아프리카 야생 동물 지역을 관광하는 것이 끝난 후에 Jungle 카페에서 1시간의 점심시간이 있을 것입니다. 모든 분들이 식사를 마치면, 우리는 아시아 야생 동물 지역으로 계속 가면서 관광을 다시 시작할 것입니다. 자, 저를 따라오시면, 관광을 시작하겠습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test10_80-82.mp3", "qs": [{"n": 80, "q": "What will open on April 14?", "opts": ["A department store", "A performance arts theater", "A dining facility", "A child care center"], "ans": 2, "ko": "4월 14일에 무엇이 개업할 것인가?"}, {"n": 81, "q": "According to the speaker, what is located on the fifth floor?", "opts": ["An exhibit space", "An information booth", "A clothing boutique", "A play area"], "ans": 3, "ko": "화자에 따르면, 5층에 무엇이 위치해 있는가?"}, {"n": 82, "q": "Why does the speaker say, \"Singer Jacob Keeve will be on site this Saturday\"?", "opts": ["To announce a concert", "To attract some shoppers", "To confirm some rumors", "To correct a mistake"], "ans": 1, "ko": "화자는 왜 \"가수 Jacob Keeve가 이번 주 토요일에 현장에 있을 것입니다\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Are you looking for something fun to do this weekend? Then stop by Plaza Mall to celebrate the grand opening of our new food hall on Saturday, April 14! Located beside our indoor playground on the fifth floor, the food hall includes 17 restaurants serving a variety of dishes from all over the world. Still not sure if you should stop by? Singer Jacob Keeve will be on site this Saturday. He will be signing copies of his latest album on the ground floor. Visit our Web site for details about this event.", "ko": "이번 주말에 할 재미있는 무언가를 찾고 계시나요? 그렇다면 4월 14일 토요일에 저희의 새로운 식품관 개장을 기념하기 위해 Plaza 쇼핑몰에 들르십시오! 5층에 있는 실내 놀이터 옆에 위치한 식품관은 전 세계의 다양한 음식들을 제공하는 17개의 음식점들을 포함합니다. 아직도 들러야 할지 확실하지 않으신가요? 가수 Jacob Keeve가 이번 주 토요일에 현장에 있을 것입니다. 그는 1층에서 자신의 최신 앨범들에 사인을 할 것입니다. 이 행사에 대한 자세한 사항을 위해서는 저희 웹사이트를 방문해 주세요."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test10_83-85.mp3", "qs": [{"n": 83, "q": "According to the speaker, what did the listener do?", "opts": ["Published a story", "Asked for time off", "Returned from a trip", "Met with a supervisor"], "ans": 1, "ko": "화자에 따르면, 청자는 무엇을 했는가?"}, {"n": 84, "q": "What must be completed by the end of the week?", "opts": ["A business report", "A project proposal", "A movie review", "A magazine article"], "ans": 3, "ko": "이번 주말까지 무엇이 완료되어야 하는가?"}, {"n": 85, "q": "What is the listener told to give a colleague?", "opts": ["Uncompleted drafts", "Contact details", "Office keys", "Itinerary information"], "ans": 0, "ko": "청자는 동료에게 무엇을 주도록 요청되는가?"}], "script": [{"sp": "M", "en": "Hello, Kathryn. This is James Hartman from the editorial office. The human resources department just notified me that they've approved your leave request. However, your article on extreme sports activities must be finished before you complete your shift on Friday. This is very important, as the piece is going to be included in next month's magazine edition. Also, your team member, Joanne Marr, is going to take over responsibility for your other work while you're away. So, please share any notes or unfinished versions of next month's story that you have with her. Feel free to drop by my office if you have any questions. Otherwise, we'll talk again when you return.", "ko": "안녕하세요, Kathryn. 저는 편집실의 James Hartman입니다. 방금 인사부에서 당신의 휴가 요청을 승인했다는 것을 저에게 알려주었습니다. 하지만, 극한 스포츠 활동에 대한 당신의 기사는 금요일에 근무 시간을 마치기 전에 반드시 완료돼야 합니다. 그 기사가 잡지의 다음 달 호에 포함될 것이기 때문에, 이것은 매우 중요합니다. 또한, 당신의 팀원인 Joanne Marr가 당신이 떠나 있는 동안 당신의 다른 업무에 대한 책임을 인계받을 것입니다. 따라서, 당신이 가지고 있는 메모나 다음 달 이야기의 미완성된 버전을 그녀에게 공유해주세요. 질문이 있으시면 언제든 제 사무실에 들르세요. 그렇지 않으면, 당신이 돌아온 후에 다시 이야기합시다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test10_86-88.mp3", "qs": [{"n": 86, "q": "What is taking place?", "opts": ["A corporate gathering", "A teaching workshop", "A lecture series", "A college orientation"], "ans": 2, "ko": "무엇이 일어나고 있는가?"}, {"n": 87, "q": "What is mentioned about the event?", "opts": ["It was organized by students.", "It will be streamed online.", "It has been extended considerably.", "It will feature several presenters."], "ans": 3, "ko": "행사에 관해 무엇이 언급되는가?"}, {"n": 88, "q": "What does the speaker recommend listeners do?", "opts": ["Get a handout from a booth", "Select their own seats", "Register for a special event", "Ask questions during a talk"], "ans": 0, "ko": "화자는 청자들에게 무엇을 하라고 권하는가?"}], "script": [{"sp": "W", "en": "It is my pleasure to welcome you all to the opening day of Keller University's scientific lecture series. We have invited a variety of scientific experts from the fields of biology, chemistry, and physics to elaborate on their most current studies and findings. I am sure you will find all four of today's talks very educational. I encourage everyone to pick up programs for today's event at the information booth near the main entrance. Also, we request that you wait until the conclusion of each lecture to ask questions. Each speaker will have an opportunity to address inquiries following his or her talk. Thank you, and I hope you enjoy the event.", "ko": "Keller 대학의 과학 강연 시리즈의 첫날에 여러분 모두를 환영하게 되어 기쁩니다. 저희는 자신들의 가장 최근의 연구와 조사 결과들에 대해 상세히 설명해 주실 생물학, 화학, 그리고 물리학 분야의 다양한 과학 전문가들을 초청했습니다. 저는 여러분이 오늘의 네 가지 강연 모두 매우 교육적이라고 여기실 것을 확신합니다. 저는 모든 분들이 중앙 출입구 근처의 안내 부스에서 오늘 행사의 일정표를 가져오실 것을 권합니다. 또한, 저희는 여러분이 질문을 하기 위해 각 강연의 끝까지 기다려주시기를 요청합니다. 각 발표자는 자신의 강연 뒤에 질문들을 다룰 기회를 가질 것입니다. 감사드리며, 행사를 즐기시기 바랍니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test10_89-91.mp3", "qs": [{"n": 89, "q": "Who most likely is the speaker?", "opts": ["A business partner", "A travel agent", "A personal assistant", "An airline attendant"], "ans": 1, "ko": "화자는 누구인 것 같은가?"}, {"n": 90, "q": "Why does the speaker say, \"there's a departure at 1:00 P.M.\"?", "opts": ["To agree to an itinerary", "To correct outdated information", "To verify a booking", "To propose an alternative"], "ans": 3, "ko": "화자는 왜 \"오후 1시 출발 편이 있습니다\"라고 말하는가?"}, {"n": 91, "q": "What does the speaker want the listener to do?", "opts": ["Notify him of a choice", "Print a new boarding pass", "Contact an airline directly", "Cancel an existing booking"], "ans": 0, "ko": "화자는 청자가 무엇을 하기를 원하는가?"}], "script": [{"sp": "M", "en": "Hello, Ms. Cooper. This is Trevor from Fairfield International Bookings returning your call about a last-minute flight to Paris tomorrow. Scheduling a morning flight is going to be hard, but there's a departure at 1:00 P.M. You'd have a three-hour layover in Brussels and eventually reach your destination at 11:00 P.M. I'll be available throughout the day, so call me back at your convenience to let me know if that will work for you. Thank you.", "ko": "안녕하세요, Ms. Cooper. 저는 Fairfield 국제 예약 대행사의 Trevor이며 내일 파리로 가는 막바지 항공편에 대한 귀하의 전화에 답변드립니다. 아침 항공편으로 일정을 잡는 것은 어렵겠지만, 오후 1시 출발 편이 있습니다. 귀하께서는 브뤼셀에서 3시간 동안 내리셨다가 최종적으로 오후 11시에 목적지에 도착하실 것입니다. 저는 온종일 연락이 가능할 테니, 편하신 때에 다시 전화 주셔서 그것이 귀하께 맞을지 알려주세요. 감사합니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test10_92-94.mp3", "qs": [{"n": 92, "q": "What has been planned for August 3?", "opts": ["A gardening convention", "An annual banquet", "A grand opening", "A charity run"], "ans": 3, "ko": "8월 3일에 무엇이 계획되어 있는가?"}, {"n": 93, "q": "What can listeners do online?", "opts": ["Look up some directions", "Learn about a community project", "Complete a registration process", "Join an organization"], "ans": 2, "ko": "청자들은 온라인으로 무엇을 할 수 있는가?"}, {"n": 94, "q": "According to the speaker, what are people able to do?", "opts": ["Share ideas with city officials", "Support a cause financially", "Design some event flyers", "Encourage others to participate"], "ans": 1, "ko": "화자에 따르면, 사람들은 무엇을 할 수 있는가?"}], "script": [{"sp": "W", "en": "Good morning. I'm Sandra Choi with Channel 11 News. On Saturday, August 3, an organization called Our Natural Resources will be holding a five-kilometer run in Chicago. The goal of the event is to raise funds for the maintenance of public parks around the city. Organizers expect thousands of people to participate in the race and hope to generate nearly one million dollars. Online registration for the run will remain open until August 1, so there are still three weeks to sign up. Financial contributions are also being accepted from those who cannot attend the event but would like to offer support.", "ko": "안녕하세요. Channel 11 뉴스의 Sandra Choi입니다. 8월 3일 토요일에, Our Natural Resources라고 불리는 한 단체가 시카고에서 5킬로미터 달리기를 개최할 예정입니다. 행사의 목적은 도시 주변 공원들의 보수를 위한 기금을 모으는 것입니다. 주최자들은 수천 명의 사람들이 경주에 참가할 것으로 예상하며, 거의 백만 달러를 만들어 내기를 기대합니다. 달리기를 위한 온라인 등록은 8월 1일까지 열려 있을 것이므로, 등록하려면 아직 3주가 있습니다. 행사에 참석하지 못하지만 후원을 제공하고자 하시는 분들로부터 재정적 기부도 받고 있습니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test10_95-97.mp3", "qs": [{"n": 95, "q": "According to the speaker, what is available online?", "opts": ["Product information", "Billing support", "Purchasing assistance", "Telephone numbers"], "ans": 0, "ko": "화자에 따르면, 온라인에서 무엇이 이용 가능한가?"}, {"n": 96, "q": "Look at the graphic. Who is on the corporate sales team?", "opts": ["Peter Gold", "Laura Hargroder", "Sven Harma", "Margaret Carruth"], "ans": 1, "ko": "시각 자료를 보시오. 누가 기업 영업팀에 있는가?"}, {"n": 97, "q": "According to the speaker, why should listeners stay on the line?", "opts": ["To check an order", "To submit a payment", "To reach an employee", "To leave a message"], "ans": 3, "ko": "화자에 따르면, 청자들은 왜 전화를 끊지 말고 기다려야 하는가?"}], "script": [{"sp": "M", "en": "Thank you for calling Fanli Technologies. To learn more about our home entertainment systems, please visit our Web site at www.fanlitech.com, where you will find product descriptions, manuals, and warranty information. If you know the extension of the person to whom you wish to speak, you may dial it at any time. To speak to one of our product management team, please dial 1099. To speak to a member of our corporate sales team, please dial 1220. To speak to someone in our accounting department about billing or payments, please dial 1330. For general inquiries, press 0 to be connected to the next available operator. If you are calling after business hours, please stay on the line to record a message. Thank you.", "ko": "Fanli Technologies사에 전화주셔서 감사합니다. 저희의 가정용 오락 기기 시스템에 대해 더 알고 싶으시다면, 제품 설명, 설명서, 그리고 품질 보증 정보를 확인하실 수 있는 저희의 웹사이트 www.fanlitech.com을 방문해 주세요. 통화하고자 하시는 사람의 내선 번호를 알고 계신다면, 언제든지 누르셔도 됩니다. 저희의 제품 관리팀 중 한 명에게 이야기하시려면, 1099번을 눌러주세요. 기업 영업팀의 직원과 이야기하시기 위해서는, 1220번을 눌러주세요. 청구서 발부나 납부에 대해 회계 부서의 누군가와 이야기하시기 위해서는, 1330번을 눌러주세요. 일반적인 문의들을 위해서는, 전화를 받을 수 있는 다음 교환원에게 연결될 수 있도록 0번을 누르세요. 영업시간 이후에 전화를 하셨다면, 메시지를 녹음하기 위해 전화를 끊지 말고 기다려주세요. 감사합니다."}], "gimg": "hk2_t10_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "캐나다식 발음", "audio": "Test10_98-100.mp3", "qs": [{"n": 98, "q": "According to the speaker, what was discussed in a letter?", "opts": ["A newly launched lineup", "A firm's financial difficulties", "A company's expansion plans", "A quarterly profit goal"], "ans": 1, "ko": "화자에 따르면, 편지에서 무엇이 논해졌는가?"}, {"n": 99, "q": "What is mentioned about Giselle Bram?", "opts": ["She arranged a press conference.", "She was hired earlier this month.", "She hopes to hear from stakeholders.", "She is a business leader."], "ans": 3, "ko": "Giselle Bram에 관해 무엇이 언급되는가?"}, {"n": 100, "q": "Look at the graphic. Which model is going to be eliminated?", "opts": ["Edge", "Veer EX", "Sabra", "Nexus I"], "ans": 0, "ko": "시각 자료를 보시오. 어느 모델이 없어질 것인가?"}], "script": [{"sp": "M", "en": "Now for our morning business update on WKSR Talk Radio. Oregon-based car manufacturer Aster attracted attention over the weekend when a letter it sent to shareholders was leaked to the press. The letter primarily addressed the company's ongoing financial struggles. But that's not all. In addition to detailing persistent quarterly losses, Aster CEO Giselle Bram outlined the company's plan for the future. To the surprise of many, the most poorly reviewed hatchback model is expected to be dropped from production this summer. Although Aster has yet to publicly respond to inquiries regarding the matter, experts who are familiar with the company believe the reports are likely to be true.", "ko": "이제 저희 WKSR 토크 라디오의 아침 경제 최신 정보 시간입니다. 오리건에 기반을 둔 자동차 제조업체인 Aster사는 그들이 주주들에게 보낸 편지가 언론에 유출된 주말 동안 화제가 되었습니다. 그 편지는 주로 그 회사의 진행 중인 재정적 분투를 다루었습니다. 그러나 그것이 전부가 아닙니다. 지속적인 분기별 적자를 열거하는 것과 더불어, Aster사의 최고 경영자인 Giselle Bram은 미래에 대한 회사의 계획의 윤곽을 보여주었습니다. 많은 사람들에게 놀랍게도, 가장 안 좋게 평가된 해치백 모델이 이번 여름에 생산에서 배제될 것으로 예상됩니다. 비록 Aster사가 이 문제에 관한 문의들에 대해 아직 공식적으로 답변하지는 않았지만, 이 회사에 대해 잘 아는 전문가들은 그 보고서가 사실인 것 같다고 생각하고 있습니다."}], "gimg": "hk2_t10_g98.jpg"}]};
